print(not True and False) #not True is False; False and False is False
print(True or False and False) # The expression is True because of the order of operation. The 'and' statement is evaluated first then the "OR" expressiona and for 'OR' you only need for one expressiont to be true.
print(not (5 > 3)) # 5 is greater than 3 which is True; but the not makes it False 
print(10 == 10 and 4 != 4) # 10==10 is True; and 4!=4 is False so the expression is False because with an "and" expression they both have to be true
print(not False or not True) # With an OR expression only  one statement has to be True.